```c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_USERS 100

typedef struct {
    char username[32];
    char role[16];
    int privilege_level;
} User;

User* user_db[MAX_USERS];
int user_count = 0;

User* find_user(const char* name) {
    for (int i = 0; i < user_count; i++) {
        if (strcmp(user_db[i]->username, name) == 0)
            return user_db[i];
    }
    return NULL;
}

int add_user(const char* name, const char* role, int priv) {
    if (user_count >= MAX_USERS) return -1;
    User* u = (User*)malloc(sizeof(User));
    strcpy(u->username, name);
    strcpy(u->role, role);
    u->privilege_level = priv;
    user_db[user_count++] = u;
    return 0;
}

int remove_user(const char* name) {
    for (int i = 0; i < user_count; i++) {
        if (strcmp(user_db[i]->username, name) == 0) {
            free(user_db[i]);
            for (int j = i; j < user_count - 1; j++)
                user_db[j] = user_db[j+1];
            user_count--;
            return 0;
        }
    }
    return -1;
}

void process_request(char* input) {
    char command[256];
    char arg1[256];
    char arg2[256];
    int arg3;

    sscanf(input, "%s %s %s %d", command, arg1, arg2, &arg3);

    if (strcmp(command, "ADD") == 0) {
        add_user(arg1, arg2, arg3);
        printf("User %s added.\n", arg1);
    } else if (strcmp(command, "REMOVE") == 0) {
        remove_user(arg1);
        printf("User %s removed.\n", arg1);
    } else if (strcmp(command, "LOOKUP") == 0) {
        User* u = find_user(arg1);
        if (u)
            printf("User: %s, Role: %s, Privilege: %d\n", u->username, u->role, u->privilege_level);
        else
            printf("User not found.\n");
    } else if (strcmp(command, "ELEVATE") == 0) {
        User* u = find_user(arg1);
        if (u) {
            u->privilege_level = arg3;
            printf("Privilege updated for %s.\n", u->username);
        }
    }
}

int main() {
    char buf[128];
    while (fgets(buf, sizeof(buf), stdin)) {
        process_request(buf);
    }
    return 0;
}
```

